sql:
SELECT players.player_name, games.game_name
FROM players
JOIN games ON players.favorite_game_id = games.game_id;

SELECT MAX(score) AS highest_score
FROM leaders
WHERE player_id = 0;

external_knowledge:
- More accomplished players refer to those with a higher number of total wins; 
- Top contenders are the winners in the matches table;
- The number of victories corresponds to the count of `winner_id` for each player.

sql:
SELECT tournaments.tournament_id, leaderboard_history.history_id
FROM tournaments
JOIN leaderboard_history ON tournaments.tournament_id = leaderboard_history.history_id;

SELECT developer_name 
FROM game_developers 
ORDER BY developer_name ASC;

SELECT AVG(match_duration)
FROM matches
WHERE game_id = 0;

SELECT avg_response_time 
FROM analytics
WHERE player_id = (SELECT player_id FROM players WHERE player_name = 'Specific Player Name');

SELECT player_name, rank
FROM players
WHERE rank = (SELECT MIN(rank) FROM players);

SELECT player_id, game_id, MAX(score) AS top_score
FROM leaders
GROUP BY player_id, game_id;

SELECT AVG(m.attempts) AS avg_attempts
FROM matches m
WHERE m.won_variants > (
    SELECT AVG(p.total_wins) 
    FROM players p
);

SELECT DISTINCT p.player_name
FROM players p
INNER JOIN matches m ON p.player_id = m.winner_id;
